 294→fn read_last_session_hint(data_dir: &Path) -> Option<String> {
 295→    let path = data_dir.join("last_session");
 296→    let raw = std::fs::read_to_string(path).ok()?;
 297→    let session = raw.trim();
 298→    if session.is_empty() {
 299→        None
 300→    } else {
 301→        Some(session.to_owned())
 302→    }
 303→}
 304→
 305→fn persist_last_session_hint(data_dir: &Path, session: &str) -> anyhow::Result<()> {
 306→    std::fs::create_dir_all(data_dir)?;
 307→    std::fs::write(data_dir.join("last_session"), session)?;
 308→    Ok(())
 309→}
