 348→/// Build provider from resolved configuration.
 349→fn build_provider(resolved: &ResolvedConfig) -> anyhow::Result<Arc<dyn Provider>> {
 350→    let pc = resolved.provider_config.as_ref();
 351→
 352→    match resolved.provider.as_str() {
 353→        "mock" => {
 354→            tracing::warn!("Provider: MockProvider (forced via config)");
 355→            Ok(Arc::new(MockProvider))
 356→        }
 357→        "openai" | "codex" | "openai-codex" => {
 358→            // Try OAuth credential first, then fall back to env var / resolved config.
 359→            if let Some(p) = try_openai_oauth_provider() {
 360→                return Ok(p);
 361→            }
 362→            let config = arcan_provider::openai::OpenAiConfig::openai_from_resolved(
 363→                resolved.model.as_deref(),
 364→                pc.and_then(|p| p.base_url.as_deref()),
 365→                pc.and_then(|p| p.max_tokens),
 366→            )?;
 367→            tracing::info!(model = %config.model, "Provider: OpenAI");
 368→            Ok(Arc::new(
 369→                arcan_provider::openai::OpenAiCompatibleProvider::new(config),
 370→            ))
 371→        }
 372→        "ollama" => {
 373→            let config = arcan_provider::openai::OpenAiConfig::ollama_from_resolved(
 374→                resolved.model.as_deref(),
 375→                pc.and_then(|p| p.base_url.as_deref()),
 376→                pc.and_then(|p| p.max_tokens),
 377→                pc.and_then(|p| p.enable_streaming),
 378→            )?;
 379→            tracing::info!(model = %config.model, base_url = %config.base_url, "Provider: Ollama");
 380→            Ok(Arc::new(
 381→                arcan_provider::openai::OpenAiCompatibleProvider::new(config),
 382→            ))
 383→        }
 384→        "anthropic" => {
 385→            let config = AnthropicConfig::from_resolved(
 386→                resolved.model.as_deref(),
 387→                pc.and_then(|p| p.base_url.as_deref()),
 388→                pc.and_then(|p| p.max_tokens),
 389→            )?;
 390→            tracing::info!(model = %config.model, "Provider: Anthropic");
 391→            Ok(Arc::new(AnthropicProvider::new(config)))
 392→        }
 393→        // Auto-detect: try providers in order
 394→        _ => {
 395→            if let Ok(config) = AnthropicConfig::from_env() {
 396→                tracing::info!(model = %config.model, "Provider: Anthropic (auto-detected)");
 397→                Ok(Arc::new(AnthropicProvider::new(config)))
 398→            } else if let Some(p) = try_openai_oauth_provider() {
 399→                Ok(p)
 400→            } else if let Ok(config) = arcan_provider::openai::OpenAiConfig::openai_from_env() {
 401→                tracing::info!(model = %config.model, "Provider: OpenAI (auto-detected)");
 402→                Ok(Arc::new(
 403→                    arcan_provider::openai::OpenAiCompatibleProvider::new(config),
 404→                ))
 405→            } else {
 406→                tracing::warn!(
 407→                    "Provider: MockProvider (set ARCAN_PROVIDER or API key env vars for real LLM)"
 408→                );
 409→                Ok(Arc::new(MockProvider))
 410→            }
 411→        }
 412→    }
 413→}
