 415→fn run_serve(
 416→    data_dir: &Path,
 417→    resolved: &ResolvedConfig,
 418→    console_dir: Option<PathBuf>,
 419→) -> anyhow::Result<()> {
 420→    let workspace_root = std::env::current_dir()?;
 421→
 422→    // --- Lago persistence ---
 423→    let journal_path = data_dir.join("journal.redb");
 424→    let blobs_path = data_dir.join("blobs");
 425→    std::fs::create_dir_all(&blobs_path)?;
 426→
 427→    tracing::info!(
 428→        workspace = %workspace_root.display(),
 429→        journal = %journal_path.display(),
 430→        blobs = %blobs_path.display(),
 431→        provider = %resolved.provider,
 432→        model = ?resolved.model,
 433→        port = resolved.port,
 434→        "Starting arcan"
 435→    );
 436→
 437→    let journal = RedbJournal::open(&journal_path)?;
 438→    let _blob_store = Arc::new(lago_store::BlobStore::open(&blobs_path)?);
 439→    let journal: Arc<dyn lago_core::Journal> = Arc::new(journal);
 440→
 441→    // --- Policies ---
 442→    let fs_policy = FsPolicy::new(workspace_root.clone());
 443→    let sandbox_policy = SandboxPolicy {
 444→        workspace_root: workspace_root.clone(),
 445→        shell_enabled: true,
 446→        network: NetworkPolicy::AllowAll,
 447→        allowed_env: BTreeSet::new(),
 448→        max_execution_ms: 10_000,
 449→        max_stdout_bytes: 1024 * 1024,
 450→        max_stderr_bytes: 1024 * 1024,
 451→        max_processes: 10,
 452→        max_memory_mb: 512,
 453→    };
 454→
 455→    // --- Tools ---
 456→    let mut registry = ToolRegistry::default();
 457→    registry.register(ReadFileTool::new(fs_policy.clone()));
 458→    registry.register(WriteFileTool::new(fs_policy.clone()));
 459→    registry.register(ListDirTool::new(fs_policy.clone()));
 460→    registry.register(EditFileTool::new(fs_policy.clone()));
 461→    registry.register(GlobTool::new(fs_policy.clone()));
 462→    registry.register(GrepTool::new(fs_policy));
 463→
 464→    let runner = Box::new(LocalCommandRunner);
 465→    registry.register(BashTool::new(sandbox_policy, runner));
 466→
 467→    let memory_dir = data_dir.join("memory");
 468→    std::fs::create_dir_all(&memory_dir)?;
 469→    registry.register(ReadMemoryTool::new(memory_dir.clone()));
 470→    registry.register(WriteMemoryTool::new(memory_dir));
 471→
 472→    // --- Governed memory tools (event-sourced via Lago) ---
 473→    let memory_projection = Arc::new(RwLock::new(MemoryProjection::new()));
 474→    registry.register(MemoryQueryTool::new(memory_projection));
 475→    registry.register(MemoryProposeTool::new(journal.clone()));
 476→    registry.register(MemoryCommitTool::new(journal.clone()));
 477→
 478→    // --- Provider ---
 479→    let provider = build_provider(resolved)?;
 480→
 481→    // Swappable handle for live provider switching
 482→    let provider_handle: arcan_core::runtime::SwappableProviderHandle =
 483→        Arc::new(std::sync::RwLock::new(provider));
 484→    let provider_factory: Arc<dyn arcan_core::runtime::ProviderFactory> =
 485→        Arc::new(factory::ArcanProviderFactory);
 486→
 487→    // --- Canonical aiOS runtime adapters ---
 488→    let event_store: Arc<dyn EventStorePort> =
 489→        Arc::new(LagoAiosEventStoreAdapter::new(journal.clone()));
 490→    // Shared handle: starts empty, filled after runtime creation.
 491→    let streaming_sender: StreamingSenderHandle = Arc::new(std::sync::Mutex::new(None));
 492→    let provider_adapter: Arc<dyn ModelProviderPort> = Arc::new(ArcanProviderAdapter::from_handle(
 493→        provider_handle.clone(),
 494→        registry.definitions(),
 495→        streaming_sender.clone(),
 496→    ));
 497→    let observer = Arc::new(LakeFsObserver {
 498→        workspace_root: workspace_root.clone(),
 499→        journal: journal.clone(),
 500→        blob_store: _blob_store,
 501→    });
 502→    let tool_harness: Arc<dyn ToolHarnessPort> =
 503→        Arc::new(ArcanHarnessAdapter::new(registry).with_observer(observer));
 504→    let policy_gate: Arc<dyn PolicyGatePort> =
 505→        Arc::new(ArcanPolicyAdapter::new(aios_protocol::PolicySet::default()));
 506→    let approvals: Arc<dyn ApprovalPort> = Arc::new(ArcanApprovalAdapter::new());
 507→
 508→    let runtime = Arc::new(KernelRuntime::new(
 509→        RuntimeConfig::new(data_dir.to_path_buf()),
 510→        event_store,
 511→        provider_adapter,
 512→        tool_harness,
 513→        approvals,
 514→        policy_gate,
 515→    ));
 516→
 517→    // Wire the broadcast sender now that the runtime exists.
 518→    *streaming_sender.lock().unwrap() = Some(runtime.event_sender());
 519→
 520→    // Build provider stack and blocking HTTP clients before entering Tokio runtime.
 521→    let data_dir_owned = data_dir.to_path_buf();
 522→    let port = resolved.port;
 523→    let tokio_runtime = tokio::runtime::Builder::new_multi_thread()
 524→        .enable_all()
 525→        .build()?;
 526→
 527→    tokio_runtime.block_on(async move {
 528→        // --- HTTP Server ---
 529→        let mut router = create_canonical_router(runtime, provider_handle, provider_factory);
 530→
 531→        // --- Console UI ---
 532→        #[cfg(feature = "console")]
 533→        {
 534→            let console_config = arcan_console::ConsoleConfig {
 535→                override_dir: console_dir,
 536→            };
 537→            router = router.nest("/console", arcan_console::console_router(console_config));
 538→        }
 539→
 540→        // --- CORS (for dev mode with separate Vite server) ---
 541→        let cors = tower_http::cors::CorsLayer::permissive();
 542→        let router = router.layer(cors);
 543→
 544→        let addr = std::net::SocketAddr::from(([127, 0, 0, 1], port));
 545→        let listener = TcpListener::bind(addr).await?;
 546→
 547→        tracing::info!(%addr, "Listening");
 548→        axum::serve(listener, router)
 549→            .with_graceful_shutdown(shutdown_signal())
 550→            .await?;
 551→
 552→        // Clean up PID file on graceful shutdown.
 553→        daemon::remove_pid_file(&data_dir_owned);
 554→
 555→        tracing::info!("Server shut down gracefully");
 556→        Ok(())
 557→    })
 558→}
