 560→async fn run_chat(
 561→    data_dir: PathBuf,
 562→    resolved: &ResolvedConfig,
 563→    session: Option<String>,
 564→    url: Option<String>,
 565→) -> anyhow::Result<()> {
 566→    // Ensure daemon is running first to avoid redb lock conflicts.
 567→    let base_url = match url {
 568→        Some(u) => u,
 569→        None => {
 570→            daemon::ensure_daemon(
 571→                &data_dir,
 572→                resolved.port,
 573→                Some(resolved.provider.as_str()).filter(|s| !s.is_empty()),
 574→                resolved.model.as_deref(),
 575→            )
 576→            .await?
 577→        }
 578→    };
 579→
 580→    // Resolve session via API (no direct journal access).
 581→    let session = resolve_session(&data_dir, session, Some(&base_url)).await;
 582→    tracing::info!(session = %session, "launching TUI");
 583→
 584→    if let Err(error) = persist_last_session_hint(&data_dir, &session) {
 585→        tracing::warn!(%error, "failed to persist last_session hint");
 586→    }
 587→
 588→    arcan_tui::run_tui(base_url, session).await
 589→}
