 591→async fn run_message(
 592→    data_dir: PathBuf,
 593→    resolved: &ResolvedConfig,
 594→    message: String,
 595→    session: Option<String>,
 596→    url: Option<String>,
 597→    json_output: bool,
 598→) -> anyhow::Result<()> {
 599→    // Ensure daemon is running first.
 600→    let base_url = match url {
 601→        Some(u) => u,
 602→        None => {
 603→            daemon::ensure_daemon(
 604→                &data_dir,
 605→                resolved.port,
 606→                Some(resolved.provider.as_str()).filter(|s| !s.is_empty()),
 607→                resolved.model.as_deref(),
 608→            )
 609→            .await?
 610→        }
 611→    };
 612→
 613→    // Resolve session via API (no direct journal access).
 614→    let session = resolve_session(&data_dir, session, Some(&base_url)).await;
 615→
 616→    if let Err(error) = persist_last_session_hint(&data_dir, &session) {
 617→        tracing::warn!(%error, "failed to persist last_session hint");
 618→    }
 619→
 620→    let exit_code = cli_run::run_cli(
 621→        &base_url,
 622→        &session,
 623→        &message,
 624→        json_output,
 625→        resolved.model.as_deref(),
 626→    )
 627→    .await?;
 628→    if exit_code != 0 {
 629→        std::process::exit(exit_code);
 630→    }
 631→    Ok(())
 632→}
