 635→fn run_config(data_dir: &Path, action: ConfigAction) -> anyhow::Result<()> {
 636→    match action {
 637→        ConfigAction::Init => {
 638→            let path = config::local_config_path(data_dir);
 639→            if path.exists() {
 640→                println!("Config file already exists: {}", path.display());
 641→            } else {
 642→                std::fs::create_dir_all(data_dir)?;
 643→                std::fs::write(&path, config::default_config_content())?;
 644→                println!("Created config: {}", path.display());
 645→            }
 646→        }
 647→        ConfigAction::Set { key, value } => {
 648→            let mut cfg = config::load_config(data_dir);
 649→            cfg.set_key(&key, &value)
 650→                .map_err(|e| anyhow::anyhow!("{e}"))?;
 651→            config::save_config(data_dir, &cfg)?;
 652→            println!("{key} = {value}");
 653→        }
 654→        ConfigAction::Get { key } => {
 655→            let cfg = config::load_config(data_dir);
 656→            match cfg.get_key(&key) {
 657→                Some(value) => println!("{value}"),
 658→                None => println!("(not set)"),
 659→            }
 660→        }
 661→        ConfigAction::List => {
 662→            let cfg = config::load_config(data_dir);
 663→            let content = toml::to_string_pretty(&cfg)
 664→                .map_err(|e| anyhow::anyhow!("failed to serialize config: {e}"))?;
 665→            if content.trim().is_empty()
 666→                || content.trim() == "[defaults]\n\n[agent]"
 667→                || content
 668→                    .lines()
 669→                    .all(|l| l.trim().is_empty() || l.starts_with('['))
 670→            {
 671→                println!("(no config values set)");
 672→                if let Some(path) = config::global_config_path() {
 673→                    println!("Global config: {}", path.display());
 674→                }
 675→                println!(
 676→                    "Local config:  {}",
 677→                    config::local_config_path(data_dir).display()
 678→                );
 679→            } else {
 680→                print!("{content}");
 681→            }
 682→        }
 683→    }
 684→    Ok(())
 685→}
