 757→fn run_login(provider: &str, device: bool, data_dir: &Path) -> anyhow::Result<()> {
 758→    // Normalize to canonical provider name for config persistence.
 759→    let canonical = match provider {
 760→        "codex" | "openai-codex" => "openai",
 761→        other => other,
 762→    };
 763→
 764→    match provider {
 765→        "openai" | "codex" | "openai-codex" => {
 766→            if device {
 767→                arcan_provider::oauth::device_login_openai().map_err(|e| anyhow::anyhow!("{e}"))?;
 768→            } else {
 769→                arcan_provider::oauth::pkce_login_openai().map_err(|e| anyhow::anyhow!("{e}"))?;
 770→            }
 771→        }
 772→        _ => {
 773→            return Err(anyhow::anyhow!(
 774→                "Unknown provider '{provider}'. Supported: openai"
 775→            ));
 776→        }
 777→    }
 778→
 779→    // Set the provider as the new default after successful login.
 780→    let mut file_config = config::load_config(data_dir);
 781→    file_config.set_key("provider", canonical).ok();
 782→    config::save_config(data_dir, &file_config)?;
 783→    eprintln!("Default provider set to '{canonical}'");
 784→
 785→    Ok(())
 786→}
