 840→fn run_logout(provider: &str, data_dir: &Path) -> anyhow::Result<()> {
 841→    // Normalize provider name for credential lookup.
 842→    let normalized = match provider {
 843→        "codex" | "openai-codex" => "openai",
 844→        other => other,
 845→    };
 846→    arcan_provider::oauth::remove_tokens(normalized).map_err(|e| anyhow::anyhow!("{e}"))?;
 847→
 848→    // Clear the default provider if it matches the one being logged out.
 849→    let mut file_config = config::load_config(data_dir);
 850→    if file_config.defaults.provider.as_deref() == Some(normalized) {
 851→        file_config.defaults.provider = None;
 852→        config::save_config(data_dir, &file_config)?;
 853→        eprintln!("Default provider cleared");
 854→    }
 855→
 856→    eprintln!("Logged out of {provider}");
 857→    Ok(())
 858→}
