 860→fn main() -> anyhow::Result<()> {
 861→    let cli = Cli::parse();
 862→    let data_dir = resolve_data_dir(&cli.data_dir)?;
 863→
 864→    // Load layered config.
 865→    let file_config = config::load_config(&data_dir);
 866→
 867→    match cli.command {
 868→        Some(Command::Serve {
 869→            max_iterations,
 870→            approval_timeout,
 871→        }) => {
 872→            // Structured logging to stderr for daemon mode
 873→            tracing_subscriber::fmt()
 874→                .with_env_filter(EnvFilter::from_default_env())
 875→                .init();
 876→
 877→            let resolved = config::resolve(
 878→                &file_config,
 879→                cli.provider.as_deref(),
 880→                cli.model.as_deref(),
 881→                cli.port,
 882→                max_iterations,
 883→                approval_timeout,
 884→            );
 885→
 886→            run_serve(&data_dir, &resolved, cli.console_dir)
 887→        }
 888→        Some(Command::Chat { session, url }) => {
 889→            // File-based logging for TUI mode (don't clobber the terminal)
 890→            let log_dir = data_dir.join("logs");
 891→            std::fs::create_dir_all(&log_dir)?;
 892→            let file_appender = tracing_appender::rolling::never(&log_dir, "tui.log");
 893→            tracing_subscriber::fmt()
 894→                .with_writer(file_appender)
 895→                .with_env_filter(EnvFilter::from_default_env())
 896→                .init();
 897→
 898→            let resolved = config::resolve(
 899→                &file_config,
 900→                cli.provider.as_deref(),
 901→                cli.model.as_deref(),
 902→                cli.port,
 903→                None,
 904→                None,
 905→            );
 906→
 907→            let runtime = tokio::runtime::Builder::new_multi_thread()
 908→                .enable_all()
 909→                .build()?;
 910→            runtime.block_on(run_chat(data_dir, &resolved, session, url))
 911→        }
 912→        Some(Command::Login { provider, device }) => run_login(&provider, device, &data_dir),
 913→        Some(Command::Logout { provider }) => run_logout(&provider, &data_dir),
 914→        Some(Command::Api { url, output }) => {
 915→            let resolved = config::resolve(
 916→                &file_config,
 917→                cli.provider.as_deref(),
 918→                cli.model.as_deref(),
 919→                cli.port,
 920→                None,
 921→                None,
 922→            );
 923→
 924→            let runtime = tokio::runtime::Builder::new_multi_thread()
 925→                .enable_all()
 926→                .build()?;
 927→            runtime.block_on(run_api(data_dir, &resolved, url, output))
 928→        }
 929→        Some(Command::Run {
 930→            message,
 931→            session,
 932→            url,
 933→            json,
 934→        }) => {
 935→            // File-based logging for CLI mode (don't clobber stdout)
 936→            let log_dir = data_dir.join("logs");
 937→            std::fs::create_dir_all(&log_dir)?;
 938→            let file_appender = tracing_appender::rolling::never(&log_dir, "run.log");
 939→            tracing_subscriber::fmt()
 940→                .with_writer(file_appender)
 941→                .with_env_filter(EnvFilter::from_default_env())
 942→                .init();
 943→
 944→            let resolved = config::resolve(
 945→                &file_config,
 946→                cli.provider.as_deref(),
 947→                cli.model.as_deref(),
 948→                cli.port,
 949→                None,
 950→                None,
 951→            );
 952→
 953→            let runtime = tokio::runtime::Builder::new_multi_thread()
 954→                .enable_all()
 955→                .build()?;
 956→            runtime.block_on(run_message(
 957→                data_dir, &resolved, message, session, url, json,
 958→            ))
 959→        }
 960→        Some(Command::Config { action }) => run_config(&data_dir, action),
 961→        Some(Command::Status) => {
 962→            let resolved = config::resolve(
 963→                &file_config,
 964→                cli.provider.as_deref(),
 965→                cli.model.as_deref(),
 966→                cli.port,
 967→                None,
 968→                None,
 969→            );
 970→
 971→            let runtime = tokio::runtime::Builder::new_multi_thread()
 972→                .enable_all()
 973→                .build()?;
 974→            runtime.block_on(run_status(&data_dir, &resolved))
 975→        }
 976→        Some(Command::Stop) => {
 977→            let resolved = config::resolve(
 978→                &file_config,
 979→                cli.provider.as_deref(),
 980→                cli.model.as_deref(),
 981→                cli.port,
 982→                None,
 983→                None,
 984→            );
 985→
 986→            let runtime = tokio::runtime::Builder::new_multi_thread()
 987→                .enable_all()
 988→                .build()?;
 989→            runtime.block_on(daemon::stop_daemon(&data_dir, resolved.port))
 990→        }
 991→        None => {
 992→            // Default: launch TUI with auto-daemon (same as `arcan chat`)
 993→            let log_dir = data_dir.join("logs");
 994→            std::fs::create_dir_all(&log_dir)?;
 995→            let file_appender = tracing_appender::rolling::never(&log_dir, "tui.log");
 996→            tracing_subscriber::fmt()
 997→                .with_writer(file_appender)
 998→                .with_env_filter(EnvFilter::from_default_env())
 999→                .init();
1000→
1001→            let resolved = config::resolve(
1002→                &file_config,
1003→                cli.provider.as_deref(),
1004→                cli.model.as_deref(),
1005→                cli.port,
1006→                None,
1007→                None,
1008→            );
1009→
1010→            let runtime = tokio::runtime::Builder::new_multi_thread()
1011→                .enable_all()
1012→                .build()?;
1013→            runtime.block_on(run_chat(data_dir, &resolved, None, None))
1014→        }
1015→    }
1016→}
