 18→fn parse_scope(s: &str) -> Result<MemoryScope, CoreError> {
 19→    match s {
 20→        "session" => Ok(MemoryScope::Session),
 21→        "user" => Ok(MemoryScope::User),
 22→        "agent" => Ok(MemoryScope::Agent),
