 34→    pub fn new(projection: Arc<RwLock<MemoryProjection>>) -> Self {
 35→        Self { projection }
 36→    }
 37→}
 38→
 39→impl Tool for MemoryQueryTool {
 40→    fn definition(&self) -> ToolDefinition {
 41→        ToolDefinition {
 42→            name: "memory_query".to_string(),
 43→            description: "Query agent memory for a given scope. Returns observations, reflections, and committed memories.".to_string(),
 44→            input_schema: json!({
 45→                "type": "object",
 46→                "properties": {
 47→                    "scope": {
 48→                        "type": "string",
 49→                        "enum": ["session", "user", "agent", "org"],
 50→                        "description": "Memory scope to query"
 51→                    },
 52→                    "limit": {
 53→                        "type": "integer",
 54→                        "description": "Maximum number of entries to return"
 55→                    }
 56→                },
 57→                "required": ["scope"]
 58→            }),
 59→            title: None,
 60→            output_schema: None,
 61→            annotations: None,
 62→            category: Some("memory".to_string()),
 63→            tags: vec!["memory".to_string()],
 64→            timeout_secs: None,
 65→        }
 66→    }
 67→
 68→    fn execute(&self, call: &ToolCall, _ctx: &ToolContext) -> Result<ToolResult, CoreError> {
 69→        let scope_str = call
 70→            .input
 71→            .get("scope")
 72→            .and_then(serde_json::Value::as_str)
 73→            .ok_or_else(|| tool_err("missing 'scope' field".to_string()))?;
 74→
 75→        let scope = parse_scope(scope_str)?;
 76→        let limit = call
 77→            .input
 78→            .get("limit")
 79→            .and_then(serde_json::Value::as_u64)
 80→            .map(|v| v as usize);
 81→
 82→        let proj = self
 83→            .projection
 84→            .read()
 85→            .map_err(|e| tool_err(format!("lock error: {e}")))?;
 86→        let result = proj.query(scope);
 87→
 88→        let observations: Vec<&String> = if let Some(lim) = limit {
 89→            result.observations.iter().take(lim).collect()
 90→        } else {
 91→            result.observations.iter().collect()
 92→        };
 93→
 94→        let committed: Vec<serde_json::Value> = result
 95→            .committed
 96→            .iter()
 97→            .map(|c| {
 98→                json!({
 99→                    "memory_id": c.memory_id,
100→                    "committed_ref": c.committed_ref,
101→                })
102→            })
103→            .collect();
104→
105→        Ok(ToolResult {
106→            call_id: call.call_id.clone(),
107→            tool_name: call.tool_name.clone(),
108→            output: json!({
109→                "entries": observations,
110→                "observation_summary": format!("{} observations", result.observations.len()),
111→                "reflection": result.reflection,
112→                "committed": committed,
113→            }),
114→            content: None,
115→            is_error: false,
116→            state_patch: None,
117→        })
118→    }
119→}
