 35→/// Middleware that captures learning events from the agent runtime.
 36→///
 37→/// Records tool failures, middleware denials, and run errors as structured
 38→/// learning entries. At the end of each run, the accumulated learnings are
 39→/// persisted to the Lago journal as `Custom` events with type "learning_captured".
 40→pub struct LearningMiddleware {
 41→    journal: Arc<dyn Journal>,
 42→    buffer: Mutex<LearningBuffer>,
 43→}
 44→
 45→impl LearningMiddleware {
 46→    pub fn new(journal: Arc<dyn Journal>) -> Self {
 47→        Self {
 48→            journal,
 49→            buffer: Mutex::new(LearningBuffer::default()),
 50→        }
 51→    }
 52→
 53→    fn push_entry(&self, entry: LearningEntry) {
 54→        if let Ok(mut buf) = self.buffer.lock() {
 55→            buf.entries.push(entry);
 56→        }
 57→    }
 58→
 59→    /// Drain the buffer and build an envelope (if any entries exist).
 60→    fn drain_to_envelope(&self) -> Result<Option<EventEnvelope>, CoreError> {
 61→        let (entries, session_id, run_id) = {
 62→            let mut buf = self.buffer.lock().map_err(|e| {
 63→                CoreError::Middleware(format!("learning buffer lock poisoned: {e}"))
 64→            })?;
 65→            let entries = std::mem::take(&mut buf.entries);
 66→            let session_id = buf.session_id.clone();
 67→            let run_id = buf.run_id.clone();
 68→            (entries, session_id, run_id)
 69→        };
 70→
 71→        if entries.is_empty() {
 72→            return Ok(None);
 73→        }
 74→
 75→        Ok(Some(EventEnvelope {
 76→            event_id: EventId::default(),
 77→            session_id: SessionId::from_string(&session_id),
 78→            branch_id: BranchId::from("main"),
 79→            run_id: Some(lago_core::id::RunId::from_string(&run_id)),
 80→            seq: 0,
 81→            timestamp: 0,
 82→            parent_id: None,
 83→            payload: EventPayload::Custom {
 84→                event_type: "learning_captured".to_string(),
 85→                data: serde_json::json!({
 86→                    "scope": MemoryScope::Agent,
 87→                    "entry_count": entries.len(),
 88→                    "entries": entries,
 89→                }),
 90→            },
 91→            metadata: Default::default(),
 92→            schema_version: 1,
 93→        }))
 94→    }
 95→
 96→    fn flush_to_journal(&self) -> Result<(), CoreError> {
 97→        let Some(envelope) = self.drain_to_envelope()? else {
 98→            return Ok(());
 99→        };
