 47→    /// Derive a lago `RiskLevel` from arcan `ToolAnnotations`.
 48→    fn risk_level(&self, tool_name: &str) -> RiskLevel {
 49→        match self.tool_annotations.get(tool_name) {
 50→            Some(ann) if ann.requires_confirmation => RiskLevel::High,
 51→            Some(ann) if ann.destructive => RiskLevel::Medium,
 52→            Some(ann) if ann.read_only => RiskLevel::Low,
 53→            _ => RiskLevel::Low,
 54→        }
 55→    }
