 79→impl Middleware for LagoPolicyMiddleware {
 80→    fn pre_tool_call(&self, context: &ToolContext, call: &ToolCall) -> Result<(), CoreError> {
 81→        let policy_ctx = self.build_context(context, call);
 82→        let decision = self.engine.evaluate(&policy_ctx);
 83→
 84→        tracing::debug!(
 85→            tool = %call.tool_name,
 86→            decision = ?decision.decision,
 87→            rule_id = ?decision.rule_id,
 88→            "Policy evaluated"
 89→        );
 90→
 91→        match decision.decision {
 92→            PolicyDecisionKind::Allow => Ok(()),
 93→            PolicyDecisionKind::Deny => {
 94→                let reason = decision
 95→                    .explanation
 96→                    .unwrap_or_else(|| "denied by policy".to_string());
 97→                Err(CoreError::Middleware(format!(
 98→                    "tool '{}' blocked: {}",
 99→                    call.tool_name, reason
100→                )))
